const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++) {
    sum = (sum + i) % 1000000007;
}
console.log(sum);

const n = parseInt(process.argv[2]);
let total = 0;
for (let i = 1; i <= n; i++) {
    let k = i;
    while (k !== 1) {
        if (k % 2 === 0) k = k / 2;
        else k = 3 * k + 1;
        total++;
    }
}
console.log(total);

function gcd(a, b) {
    while (b > 0) { const t = b; b = a % b; a = t; }
    return a;
}
const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++)
    for (let j = i; j <= n; j++)
        sum += gcd(i, j);
console.log(sum);

const n = parseInt(process.argv[2]);
let a = 0, b = 1;
for (let i = 0; i < n; i++) {
    const temp = b;
    b = (a + b) % 1000000007;
    a = temp;
}
console.log(a);

const n = parseInt(process.argv[2]);
let count = 0;
for (let i = 2; i <= n; i++) {
    let isPrime = true;
    for (let d = 2; d * d <= i; d++) {
        if (i % d === 0) { isPrime = false; break; }
    }
    if (isPrime) count++;
}
console.log(count);

const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) {
    seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648;
    arr[i] = (seed >> 16) % 1000;
}
const counts = new Array(1000).fill(0);
for (const v of arr) counts[v]++;
const sorted = [];
for (let v = 0; v < 1000; v++)
    for (let c = 0; c < counts[v]; c++)
        sorted.push(v);
let checksum = 0;
for (const v of sorted) checksum = (checksum + v) % 1000000007;
console.log(`${sorted[0]} ${sorted[n - 1]} ${checksum}`);
